import { useState } from "react";
import { useLocation } from "react-router-dom";
import styled from "styled-components";

const categories = ["celular", "headphone", "notebook", "acessorios"];

const allProducts = [
  { id: 1, name: "iPhone 15", category: "celular" ,  price: 5999, oldPrice: 6999, image: "https://via.placeholder.com/300"},
  { id: 2, name: "Galaxy S23", category: "celular", price: 4999, oldPrice: 5799, image: "https://via.placeholder.com/300" },
  { id: 3, name: "JBL 520BT", category: "headphone", price: 399, oldPrice: 499, image: "https://via.placeholder.com/300" },
  { id: 4, name: "Notebook Gamer", category: "notebook", price: 7499, oldPrice: 8199, image: "https://via.placeholder.com/300" },
  { id: 5, name: "Mouse RGB", category: "acessorios",     price: 199, oldPrice: 249,image: "https://via.placeholder.com/300" }
];

const Products = () => {
  const location = useLocation();
  const queryParams = new URLSearchParams(location.search);
  const categoriaQuery = queryParams.get("categoria");

  const [search, setSearch] = useState("");
  const [categoria, setCategoria] = useState(categoriaQuery || "");

  const filteredProducts = allProducts
    .filter(p =>
      categoria ? p.category === categoria : true
    )
    .filter(p =>
      p.name.toLowerCase().includes(search.toLowerCase())
    );

  return (
    <Container>
      <Sidebar>
        <FilterTitle>Categorias</FilterTitle>

        {categories.map(cat => (
          <FilterButton
            key={cat}
            active={categoria === cat}
            onClick={() => setCategoria(cat)}
          >
            {cat}
          </FilterButton>
        ))}

        <ClearButton onClick={() => setCategoria("")}>
          Limpar filtro
        </ClearButton>
      </Sidebar>

      <Content>
        <SearchInput
          type="text"
          placeholder="Buscar produto..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />

        <Grid>
          {filteredProducts.map(product => (
            <Card key={product.id}>
              <Image src={product.image} />
              <ProductName>{product.name}</ProductName>

              <PriceContainer>
                <OldPrice>
                  R$ {product.oldPrice}
                </OldPrice>
                <NewPrice>
                  R$ {product.price}
                </NewPrice>
              </PriceContainer>

              <BuyButton>
                Comprar
              </BuyButton>
            </Card>
          ))}
        </Grid>
      </Content>
    </Container>
  );
};
export default Products;

const Container = styled.div`
  display: flex;
  padding: 120px 80px;
  background: #0D0D0D;
  min-height: 100vh;
  gap: 60px;
`;

const Sidebar = styled.div`
  width: 220px;
  display: flex;
  flex-direction: column;
  gap: 15px;
`;

const FilterTitle = styled.h2`
  color: white;
  font-family: 'Space Grotesk';
  margin-bottom: 10px;
`;

const FilterButton = styled.button`
  padding: 10px;
  background: ${({ active }) => active ? "#7C3AED" : "#1A1A1A"};
  color: white;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  transition: 0.3s;

  &:hover {
    background: #7C3AED;
  }
`;

const ClearButton = styled.button`
  margin-top: 10px;
  padding: 8px;
  background: transparent;
  border: 1px solid #7C3AED;
  color: #7C3AED;
  border-radius: 8px;
  cursor: pointer;
`;


const Grid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
  gap: 30px;
`;

const Card = styled.div`
  background: #1A1A1A;
  padding: 20px;
  border-radius: 16px;
  text-align: center;
  transition: 0.3s;

  &:hover {
    transform: translateY(-5px);
    background: #222;
  }
`;
